from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def welcome():
    user_name = request.args.get('name', 'Guest')
    message = f'<h1>Welcome, <em>{user_name}</em>!</h1>'
    return message

if __name__ == '__main__':
    app.run()